// E-E-A-T Auditor Service
// Analyzes content for Experience, Expertise, Authoritativeness, Trustworthiness

export interface EEATFinding {
  pillar: 'experience' | 'expertise' | 'authority' | 'trust';
  status: 'present' | 'incomplete' | 'missing';
  label: string;
  description: string;
  recommendation: string;
  fixTool?: 'citation-block' | 'author-bio' | 'trust-signals' | 'about-page';
}

export interface EEATAuditResult {
  url: string;
  timestamp: string;
  scores: {
    experience: number;
    expertise: number;
    authority: number;
    trust: number;
  };
  globalScore: number;
  findings: EEATFinding[];
}

export interface EEATHistoryEntry {
  id: string;
  result: EEATAuditResult;
}

// --- LocalStorage persistence ---
const STORAGE_KEY = 'citedby_eeat_history';

export const saveAuditToHistory = (result: EEATAuditResult): void => {
  const history = getAuditHistory();
  const entry: EEATHistoryEntry = {
    id: `eeat-${Date.now()}`,
    result
  };
  history.unshift(entry);
  // Keep only last 20 entries
  const trimmed = history.slice(0, 20);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(trimmed));
};

export const getAuditHistory = (): EEATHistoryEntry[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch {
    return [];
  }
};

export const compareAudits = (current: EEATAuditResult, previous: EEATAuditResult) => {
  return {
    experience: current.scores.experience - previous.scores.experience,
    expertise: current.scores.expertise - previous.scores.expertise,
    authority: current.scores.authority - previous.scores.authority,
    trust: current.scores.trust - previous.scores.trust,
    global: current.globalScore - previous.globalScore
  };
};

// --- Deterministic Audit Simulation ---
const seedRandom = (str: string, idx: number): number => {
  let hash = 0;
  const combined = str + idx.toString();
  for (let i = 0; i < combined.length; i++) {
    hash = ((hash << 5) - hash) + combined.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash % 100);
};

const EEAT_CHECKS: Array<{
  pillar: EEATFinding['pillar'];
  label: string;
  description: string;
  recommendation: string;
  fixTool: EEATFinding['fixTool'];
}> = [
  // Experience
  { pillar: 'experience', label: 'Témoignages clients', description: 'Citations et avis de clients réels démontrant l\'expérience utilisateur', recommendation: 'Ajoutez des blocs de citations avec des témoignages clients vérifiés', fixTool: 'citation-block' },
  { pillar: 'experience', label: 'Études de cas', description: 'Cas concrets montrant les résultats obtenus', recommendation: 'Créez des études de cas détaillées avec métriques', fixTool: 'citation-block' },
  { pillar: 'experience', label: 'Preuves d\'utilisation', description: 'Screenshots, démos, vidéos de l\'expérience produit', recommendation: 'Intégrez des captures d\'écran et démonstrations', fixTool: undefined },
  // Expertise
  { pillar: 'expertise', label: 'Biographie auteur', description: 'Page auteur avec credentials et expertise démontrée', recommendation: 'Créez une biographie auteur détaillée avec qualifications', fixTool: 'author-bio' },
  { pillar: 'expertise', label: 'Contenu approfondi', description: 'Articles et guides montrant une expertise sectorielle', recommendation: 'Publiez du contenu expert avec données et analyses', fixTool: undefined },
  { pillar: 'expertise', label: 'Certifications affichées', description: 'Badges, certifications et accréditations visibles', recommendation: 'Affichez vos certifications et accréditations professionnelles', fixTool: 'trust-signals' },
  // Authority
  { pillar: 'authority', label: 'Mentions et citations', description: 'Votre marque est mentionnée par des sources tierces', recommendation: 'Développez votre stratégie de relations presse et backlinks', fixTool: 'citation-block' },
  { pillar: 'authority', label: 'Données structurées Organization', description: 'Schema.org Organization avec sameAs et knowsAbout', recommendation: 'Implémentez les données structurées Organisation', fixTool: 'trust-signals' },
  { pillar: 'authority', label: 'Présence sur sources d\'autorité', description: 'Profils vérifiés sur Wikipedia, Wikidata, Crunchbase', recommendation: 'Créez des profils sur les plateformes d\'autorité', fixTool: undefined },
  // Trust
  { pillar: 'trust', label: 'Page À propos complète', description: 'Page about avec histoire, équipe, mission', recommendation: 'Créez une page À propos transparente et complète', fixTool: 'about-page' },
  { pillar: 'trust', label: 'Mentions légales et CGV', description: 'Pages légales complètes et accessibles', recommendation: 'Assurez la présence de toutes les mentions légales', fixTool: 'about-page' },
  { pillar: 'trust', label: 'Politique de confidentialité', description: 'RGPD-compliant privacy policy', recommendation: 'Mettez à jour votre politique de confidentialité', fixTool: undefined },
];

export const runEEATAudit = async (url: string): Promise<EEATAuditResult> => {
  // Simulate processing time
  await new Promise(resolve => setTimeout(resolve, 2500));

  const findings: EEATFinding[] = EEAT_CHECKS.map((check, i) => {
    const rand = seedRandom(url, i);
    let status: EEATFinding['status'];
    if (rand > 65) status = 'present';
    else if (rand > 30) status = 'incomplete';
    else status = 'missing';

    return {
      ...check,
      status
    };
  });

  // Calculate scores per pillar
  const pillarScores = (['experience', 'expertise', 'authority', 'trust'] as const).reduce((acc, pillar) => {
    const pillarFindings = findings.filter(f => f.pillar === pillar);
    const score = Math.round(
      pillarFindings.reduce((sum, f) => {
        if (f.status === 'present') return sum + 100;
        if (f.status === 'incomplete') return sum + 50;
        return sum;
      }, 0) / pillarFindings.length
    );
    acc[pillar] = score;
    return acc;
  }, {} as Record<string, number>);

  const globalScore = Math.round(
    (pillarScores.experience + pillarScores.expertise + pillarScores.authority + pillarScores.trust) / 4
  );

  const result: EEATAuditResult = {
    url,
    timestamp: new Date().toISOString(),
    scores: {
      experience: pillarScores.experience,
      expertise: pillarScores.expertise,
      authority: pillarScores.authority,
      trust: pillarScores.trust
    },
    globalScore,
    findings
  };

  // Auto-save to history
  saveAuditToHistory(result);

  return result;
};
